before_code:
module counter_sync (
  input clk,
  input rst_n,
  input enable,
  input load,
  input [7:0] load_value,
  output reg [7:0] count
);
  always @(posedge clk) begin
    if (!rst_n)
      count <= 8'b0;
    else if (enable)
      if (load)
        count <= load_value;
      else
        count <= count + 1;
  end
endmodule

after_code:
module counter_sync (
  input clk,
  input rst_n,
  input enable,
  input load,
  input [7:0] load_value,
  output reg [7:0] count
);
  always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
      count <= 8'b0;
    else if (enable)
      if (load)
        count <= load_value;
      else
        count <= count + 1;
  end
endmodule
